job:
Create three config files for the Development Department plugin.

1. Create plugins/dev-department/package.json:
{
  "name": "dev-department",
  "version": "0.1.0",
  "description": "Development Department plugin for Paperclip",
  "main": "src/worker/index.ts",
  "author": "Mike Jackson",
  "license": "MIT",
  "dependencies": {
    "react": "^19.0.0",
    "react-dom": "^19.0.0",
    "typescript": "^5.0.0"
  },
  "devDependencies": {
    "@types/react": "^19.0.0",
    "@types/react-dom": "^19.0.0"
  }
}

2. Create plugins/dev-department/paperclip-plugin.json:
{
  "id": "dev-department",
  "apiVersion": 1,
  "version": "0.1.0",
  "displayName": "Development Department",
  "description": "Phase-aware build governance for phased architecture projects",
  "author": "Mike Jackson",
  "categories": ["productivity"],
  "capabilities": ["plugin.state.read", "plugin.state.write"],
  "entrypoints": {
    "worker": "src/worker/index.ts",
    "ui": "src/ui/index.tsx"
  },
  "ui": {
    "slots": [
      {
        "type": "projectSidebarItem",
        "id": "dev-dept-sidebar",
        "displayName": "Development Department",
        "exportName": "DepartmentSidebar",
        "entityTypes": ["project"]
      },
      {
        "type": "detailTab",
        "id": "dev-dept-phases",
        "displayName": "Phases",
        "exportName": "PhasesTab",
        "entityTypes": ["project"]
      }
    ]
  }
}

3. Create plugins/dev-department/tsconfig.json:
{
  "compilerOptions": {
    "target": "ES2020",
    "module": "ESNext",
    "moduleResolution": "bundler",
    "jsx": "react-jsx",
    "strict": true,
    "esModuleInterop": true,
    "skipLibCheck": true,
    "outDir": "dist",
    "rootDir": "src",
    "declaration": true
  },
  "include": ["src/**/*"]
}

Commit all three files.
